const hunterData = $('🔍 Hunter.io · Domain Search').item.json;
const leadData = $('🔁 Loop Over Items').item.json;

const emails = hunterData.data?.emails || [];

// Preferir contactos con roles IT/TI/Tech/Sistemas/Director/Gerente
const itKeywords = ['it', 'ti', 'tech', 'system', 'infra', 'director', 'gerente', 'manager', 'cto', 'cio', 'chief', 'head'];

const ranked = emails
  .filter(e => e.value && e.confidence >= 50)
  .map(e => {
    const fullText = ((e.first_name || '') + ' ' + (e.last_name || '') + ' ' + (e.position || '')).toLowerCase();
    const itScore = itKeywords.filter(k => fullText.includes(k)).length;
    return { ...e, itScore };
  })
  .sort((a, b) => b.itScore - a.itScore || b.confidence - a.confidence);

const best = ranked[0];

return [{
  json: {
    target_id: leadData.id,
    canonical_domain: leadData.canonical_domain,
    company_name: leadData.company_name,
    country: leadData.country,
    west_telco_product: leadData.west_telco_product,
    priority_score: leadData.priority_score,
    // Contacto encontrado
    first_contact_name: best ? `${best.first_name || ''} ${best.last_name || ''}`.trim() : null,
    first_contact_email: best?.value || null,
    contact_role: best?.position || null,
    email_confidence: best?.confidence || null,
    has_contact_email: true,
    has_contact_name: !!(best?.first_name),
    enrichment_status: 'ready',
    verification_status: 'verified',
    verification_score: best?.confidence || null,
    verification_source: 'hunter',
    verified_at: new Date().toISOString(),
    next_enrichment_step: null
  }
}];

const leadData = $('🔁 Loop Over Items').item.json;
const hunterData = $('🔍 Hunter.io · Domain Search').item.json;

return [{
  json: {
    target_id: leadData.id,
    canonical_domain: leadData.canonical_domain,
    company_name: leadData.company_name,
    west_telco_product: leadData.west_telco_product,
    enrichment_status: 'partial',
    verification_status: 'not_found',
    verification_score: 0,
    verification_source: 'hunter',
    verification_reason: `Hunter no encontró emails para ${leadData.canonical_domain}. Emails totales: ${hunterData.data?.emails?.length || 0}`,
    next_enrichment_step: 'manual_linkedin',
    verified_at: new Date().toISOString()
  }
}];

// Agregar todos los items procesados
const items = $input.all();

const ready = items.filter(i => i.json.enrichment_status === 'ready').length;
const partial = items.filter(i => i.json.enrichment_status === 'partial').length;
const errors = items.filter(i => i.json.error).length;

return [{
  json: {
    agent_name: 'enrichment_hunter',
    trigger_type: 'schedule',
    processed_count: items.length,
    success_count: ready,
    blocked_count: partial,
    error_count: errors,
    estimated_cost_usd: (items.length * 0.002).toFixed(4),
    status: 'completed',
    input_scope: { source: 'hunter', batch_size: 100 }
  }
}];
